+    #[test]
+    fn test_trace_multi_output_program() {
+        // f(x) returns (sin(x), cos(x)) — multi-output tracing
+        use super::make_jaxpr;
+        let aval = ShapedArray {
+            dtype: DType::F64,
+            shape: Shape::scalar(),
+        };
